def stream(self, messages, **kwargs) -> Iterator[str]:
    for p in self.providers:
        try:
            client = self.clients[p.name]
            stream = client.chat.completions.create(
                model=p.model, messages=messages, stream=True, **kwargs,
            )
            for chunk in stream:
                if delta := chunk.choices[0].delta.content:
                    yield delta
            return
        except Exception as e:
            print(f'[{p.name}] stream failed, falling over')
    raise RuntimeError('All providers failed')

def call_by_task(self, messages, task_type='reasoning', **kwargs):
    if task_type == 'classification':
        # Use cheapest fast provider
        return self._call_one(
            next(p for p in self.providers if p.name == 'groq'),
            messages, **kwargs)
    elif task_type == 'reasoning':
        # Use a frontier model
        return self._call_one(
            next(p for p in self.providers if p.name in ('openai', 'anthropic-oai')),
            messages, **kwargs)

